<script setup lang="ts">
import { onMounted, reactive, ref } from 'vue'; import PageHeader from '@/components/PageHeader.vue'; import StatusTag from '@/components/StatusTag.vue'; import type { AuditLog } from '@/types'; import { getAuditLog, getAuditLogs } from '@/api/audit'; import { formatUtcToLocal } from '@/utils/time'
const loading=ref(false),drawer=ref(false),rows=ref<AuditLog[]>([]),total=ref(0),current=ref<AuditLog>();const query=reactive({current:1,size:10,keyword:'',status:'',module:''});async function load(){loading.value=true;try{const p=await getAuditLogs(query);rows.value=p.records;total.value=p.total}catch{rows.value=[]}finally{loading.value=false}}function reset(){Object.assign(query,{current:1,size:query.size,keyword:'',status:'',module:''});load()}async function show(row:AuditLog){current.value=await getAuditLog(row.id);drawer.value=true}onMounted(load)
</script>
<template><div><PageHeader title="操作日志" description="只读查看证书生命周期中的关键管理行为"/><section class="panel"><div class="toolbar"><el-input v-model="query.keyword" placeholder="操作者或关联对象" clearable style="width:260px"/><el-select v-model="query.module" placeholder="操作模块" clearable style="width:150px"><el-option label="证书管理" value="证书管理"/><el-option label="可信存证" value="可信存证"/></el-select><el-select v-model="query.status" placeholder="结果" clearable style="width:130px"><el-option label="成功" value="SUCCESS"/><el-option label="失败" value="FAILED"/></el-select><el-button type="primary" @click="query.current=1;load()">查询</el-button><el-button @click="reset">重置</el-button></div><el-table v-loading="loading" :data="rows" empty-text="暂无操作日志"><el-table-column prop="operator" label="操作者"/><el-table-column prop="action" label="操作类型"/><el-table-column prop="module" label="模块"/><el-table-column prop="target" label="关联对象" min-width="180"/><el-table-column label="结果"><template #default="s"><StatusTag :value="s.row.result"/></template></el-table-column><el-table-column label="操作时间" min-width="170"><template #default="s">{{formatUtcToLocal(s.row.createdAt)}}</template></el-table-column><el-table-column label="操作"><template #default="s"><el-button link type="primary" @click="show(s.row)">详情</el-button></template></el-table-column></el-table><div class="pagination"><el-pagination v-model:current-page="query.current" v-model:page-size="query.size" :total="total" layout="total, sizes, prev, pager, next" @change="load"/></div></section><el-drawer v-model="drawer" title="日志详情"><div v-if="current" class="detail-list"><div><span>操作者</span><b>{{current.operator}}</b></div><div><span>操作</span><b>{{current.action}}</b></div><div><span>模块</span><b>{{current.module}}</b></div><div><span>关联对象</span><b>{{current.target}}</b></div><div><span>详情</span><b>{{current.detail||'—'}}</b></div><div><span>时间</span><b>{{formatUtcToLocal(current.createdAt)}}</b></div></div></el-drawer></div></template>